import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Änderungsprotokoll: Versionsentwicklung | opencode-dynamic-context-pruning","description":"Erfahren Sie mehr über die Versionshistorie des DCP-Plugins. Sehen Sie sich neue Funktionen, Verbesserungen und Bugfixes an, um Upgrades zu bewerten.","frontmatter":{"title":"Änderungsprotokoll: Versionsentwicklung | opencode-dynamic-context-pruning","sidebarTitle":"Neuerungen in neuen Versionen","subtitle":"Änderungsprotokoll: Versionsentwicklung","description":"Erfahren Sie mehr über die Versionshistorie des DCP-Plugins. Sehen Sie sich neue Funktionen, Verbesserungen und Bugfixes an, um Upgrades zu bewerten.","order":6},"headers":[],"relativePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/changelog/index.md","filePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/changelog/index.md"}'),o={name:"de/Opencode-DCP/opencode-dynamic-context-pruning/changelog/index.md"};function s(a,e,d,l,u,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="anderungsprotokoll" tabindex="-1">Änderungsprotokoll <a class="header-anchor" href="#anderungsprotokoll" aria-label="Permalink to &quot;Änderungsprotokoll&quot;">​</a></h1><p>In diesem Kapitel wird die Versionshistorie des DCP-Plugins dokumentiert, damit Sie die neuen Funktionen, Verbesserungen und Fixes jeder Version verstehen und Upgrade-Entscheidungen treffen können.</p><h2 id="kapitelinhalt" tabindex="-1">Kapitelinhalt <a class="header-anchor" href="#kapitelinhalt" aria-label="Permalink to &quot;Kapitelinhalt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seite</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./version-history/">Versionshistorie</a></td><td>Vollständige Aufzeichnung der Updates von v1.0.1 bis zur neuesten Version, einschließlich neuer Funktionen, Verbesserungen und Bugfixes</td></tr></tbody></table><h2 id="leseempfehlung" tabindex="-1">Leseempfehlung <a class="header-anchor" href="#leseempfehlung" aria-label="Permalink to &quot;Leseempfehlung&quot;">​</a></h2><p>Das Änderungsprotokoll eignet sich hauptsächlich für die folgenden Szenarien:</p><ol><li><strong>Vor dem Upgrade</strong> - Erfahren Sie, welche Änderungen die neue Version bringt, und bewerten Sie, ob ein Upgrade erforderlich ist</li><li><strong>Fehlerbehebung</strong> - Bestätigen Sie, in welcher Version eine Funktion eingeführt oder ein Bug behoben wurde</li><li><strong>Entwicklungsrichtung verstehen</strong> - Verstehen Sie durch die Versionshistorie die Entwicklung der Funktionen und die Optimierungsschwerpunkte von DCP</li></ol><div class="tip custom-block"><p class="custom-block-title">Aktuell bleiben</p><p>Es wird empfohlen, in der OpenCode-Konfiguration das Tag <code>@latest</code> zu verwenden, um automatisch die neuesten Funktionen und Fixes zu erhalten.</p></div><h2 id="verwandte-ressourcen" tabindex="-1">Verwandte Ressourcen <a class="header-anchor" href="#verwandte-ressourcen" aria-label="Permalink to &quot;Verwandte Ressourcen&quot;">​</a></h2><ul><li>Möchten Sie die Kernfunktionen von DCP verstehen? Siehe <a href="./../start/getting-started/">Installation und Schnellstart</a></li><li>Haben Sie Probleme? Siehe <a href="./../faq/troubleshooting/">Häufig gestellte Fragen und Fehlerbehebung</a></li></ul>',10)])])}const p=n(o,[["render",s]]);export{g as __pageData,p as default};
